mapper.select:
SELECT  
  FROM  TB_EVENT_INFO A
 WHERE  A.EVENT_ID = #{eventId}

mapper.insert:
INSERT  INTO TB_EVENT_INFO
      ( EVENT_ID
      , BSNS_YEAR
      , BSNS_CODE
      , EVENT_SVC_BGNDE
      , EVENT_SVC_ENDDE
      , SVC_USE_NMPR_CO
      , CHARGER_NM
      , EVENT_CN
      , EVENT_TY_CODE
      , PRPARETG_CN
      , EVENT_CONFM_AT
      , EVENT_CONFM_DE
      , FRST_REGISTER_ID
      , FRST_REGIST_PNTTM )
VALUES  ( #{eventId}
        , #{bsnsYear}
        , #{bsnsCode}
        , #{eventSvcBeginDe}
        , #{eventSvcEndDe}
        , #{svcUseNmprCo}
        , #{chargerNm}
        , #{eventCn}
        , #{eventTyCode}
        , #{prparetgCn}
        , #{eventConfmAt}
        , #{eventConfmDe}
        , #{frstRegisterId}
        , CURRENT_TIMESTAMP )

mapper.update:
UPDATE  TB_EVENT_INFO
   SET  EVENT_CN        = #{eventCn}
      , EVENT_SVC_BGNDE = #{eventSvcBeginDe}
      , EVENT_SVC_ENDDE = #{eventSvcEndDe}
      , CHARGER_NM      = #{chargerNm}
      , EVENT_CONFM_AT  = #{eventConfmAt}
      , LAST_UPDUSR_ID  = #{lastUpdusrId}
      , LAST_UPDT_PNTTM = CURRENT_TIMESTAMP
 WHERE  EVENT_ID = #{eventId}
